var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"전조 프로토콜 1시간 전","JPN":"前兆プロトコル1時間前","ENG":"1 hour before the Omen Protocol","TWN":"前兆協議1小時前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 대균열 관측소 정문","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>大亀裂観測所正門","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color> Grand Dimension Crevice Observation Post Main Entrance","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>大峽谷觀測站正門"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"전부 쏴 버려……!","JPN":"一つ残らず撃ち殺すんだ……！","ENG":"Shoot them. All of them...!","TWN":"全部射殺……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L12_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"녀석들을 대균열 영향권에 들여보내서는 안 돼!","JPN":"やつらを大亀裂の影響圏内に入らせるな！","ENG":"Don't let them enter the Grand Dimension Crevice!","TWN":"不能讓那些傢伙進入大峽谷的影響範圍！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"큭, 저항이 심하군요!","JPN":"くっ、抵抗が激しい！","ENG":"Tch, they are putting up fierce resistance!","TWN":"嘖，抵抗很激烈！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"서두르셔야 합니다, 신부님. 계시의 시간이 머지않았습니다!","JPN":"急いでください、神父様！　啓示の時まであといくらもありません！","ENG":"You must hurry, Father. The time of revelation is close!","TWN":"動作快，神父。啟示的時刻就要到了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"잘 훈련된 병사들이군. 하지만 걱정할 필요 없다.","JPN":"どの兵士もよく訓練されているな。だが心配する必要はない。","ENG":"Well-trained soldiers. But there is no need to worry.","TWN":"真是訓練有素的士兵呢，不過不用擔心。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"시니어가 살해당한 사건으로, 관측소의 경계가 삼엄해질 것쯤은 예측했으니까.","JPN":"シニアが殺された事件の影響で観測所の警戒が厳しくなっていることぐらい予測済みだ。","ENG":"After the Senior was murdered, it was only natural to expect tighter security at the observation post.","TWN":"我早就預料到觀測站會因為Senior被殺而升級警戒了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그리고 그에 대한 대비책도 마련해 두었지.","JPN":"そして対策も用意してある。","ENG":"And I have prepared countermeasures for that as well.","TWN":"而且我也準備了對策。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"대비책이라고요……?","JPN":"対策ですか……？","ENG":"Countermeasures...?","TWN":"對策是指……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"크헉……!","JPN":"かはっ……！","ENG":"Ghk...!","TWN":"咳……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"저격이다! 교전을 멈추고 엄폐물 뒤로…… ","JPN":"狙撃だ！　交戦を止め、遮蔽物に隠れ…… ","ENG":"Sniper! Cease engagement and take cov–","TWN":"是狙擊！停止交戰，躲到掩體後…… "},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"음!?","JPN":"ん！？","ENG":"Mm?!","TWN":"嗯！？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識的<color=#ff3636>盛宴</color>準備好了。<color=#ff3636>宴會</color>開始<b>了</b>。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L38_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"으, 으악! 시체에서 갑자기……!","JPN":"う、うわあっ！　急に死体から……！","ENG":"A-aargh! The corpse...!","TWN":"呃、啊啊！屍體突然……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"학회에서 부리는 침식체……?","JPN":"学会が従わせている侵食体……？","ENG":"A C.O. controlled by the Society...?","TWN":"是學會操控的侵蝕體……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"모두 후퇴! 대인 무장으로는 저것에 대응할 수 없다!","JPN":"全員後退！　対人武装ではあれに対抗できない！","ENG":"All units, fall back! Anti-personnel weapons can't deal with that!","TWN":"全員後退！對付真人的武器應付不了那個東西！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"교전 구역에서 벗어나, D-3 구역까지 후퇴! 카운터 지원을 요청하라!","JPN":"交戦区域から離脱し、D-3区域まで後退する！　カウンターの支援を要請せよ！","ENG":"Withdraw from the combat zone to Sector D-3! Request Counter support!","TWN":"撤離交戰區域，撤退到D-3區！請求制裁者支援！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CULTIST_CHARADE_YALDABAOTH_NULL","text":{"KOREA":"늦었군, 검은 신부.","JPN":"遅かったな、黒い神父。","ENG":"You are late, Black Priest.","TWN":"你遲到了，黑色神父。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CHARADE_YALDABAOTH_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L47_1","type":"dialog","speaker":"CULTIST_CHARADE_YALDABAOTH_NULL","text":{"KOREA":"계시와 그릇에 관해서는 이미 교주님께 전달받았다.","JPN":"啓示と器についてはすでに教祖様から聞いている。","ENG":"I have already received word from our leader regarding the revelation and the vessel.","TWN":"教主已經告訴我有關啟示與器皿的事了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CHARADE_YALDABAOTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CULTIST_CHARADE_YALDABAOTH_NULL","text":{"KOREA":"지금부터는 우리 얄다바오트의 자녀들이 당신에게 협조하겠다. 나를 따르도록.","JPN":"今からは我々ヤルダバオトの子供があなたに協力する。私について来たまえ。","ENG":"From this point on, the Children of Yaldabaoth will cooperate with you. Follow me.","TWN":"接下來，我們亞達巴沃的子女將會協助你。跟我來吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CHARADE_YALDABAOTH_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"잠깐.","JPN":"待て。","ENG":"Wait.","TWN":"等等。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"신부님? 어서 서둘러야 합니다.","JPN":"どうしましたか？　急がねばなりません。","ENG":"Father? We must hurry.","TWN":"神父？請快一點。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"아니, 아무래도 꼬리를 잡힌 모양이군.","JPN":"いや、どうやら尻尾を掴まれたようだ。","ENG":"No. It seems our trail has been discovered.","TWN":"不，看來是被盯上了呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CULTIST_CHARADE_YALDABAOTH_NULL","text":{"KOREA":"꼬리라고…? 그게 무슨……?","JPN":"尻尾……？　それはどういう……？","ENG":"Our trail...? What do you mean by that...?","TWN":"被盯上……？什麼意思……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CHARADE_YALDABAOTH_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L10_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_QM","text":{"KOREA":"대담하다고 해야 할지, 무모하다고 해야 할지…….","JPN":"大胆と言うべきか、無謀と言うべきか……","ENG":"Bold, or perhaps reckless...","TWN":"該說你是大膽，還是魯莽呢……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L11_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_QM","text":{"KOREA":"감히 학회가 관리하는 영지에서 이런 소란을 벌이다니…….","JPN":"学会が管理している領地でこのような騒ぎを起こすとは……","ENG":"To cause such a disturbance within the Society estate...","TWN":"竟敢在學會管理的領地鬧出這種騷動……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"수, 순식간에… 목이 떨어졌어……?","JPN":"い、一瞬で……首が落とされた……？","ENG":"H-his head was cut off... In an instant...?","TWN":"一、一瞬間……頭就落地了……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"대체 어디서……?","JPN":"いったいどこから……？","ENG":"Where did it even come from...?","TWN":"到底是從哪裡……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_QM","text":{"KOREA":"제법이군. 내 검기에 반응할 줄이야.","JPN":"私の剣気に反応するか。多少の腕はあるようだ。","ENG":"Impressive. To react to my spirit sword.","TWN":"真不錯，沒想到你對我的劍氣有反應。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_QM","text":{"KOREA":"찰나의 순간, 신체의 반사 신경을 향상시킨 건가?","JPN":"あの短い間、身体の反射神経を向上させたのか？","ENG":"Did you enhance your physical reflexes for a split second?","TWN":"你在那瞬間強化了身體的反射神經嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"과연…….","JPN":"なるほど……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"단말마조차 지르지 못하고, 목이 잘려 나가는 이 살해 방식…….","JPN":"断末魔すら許さない、一斬りで首を落とすこの殺し方……","ENG":"This method of killing, severing the head without even allowing a final scream...","TWN":"來不及發出慘叫，就被斬首的殺人手法……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"학회의 학부장이 관리국 공인 카운터급의 실력자라는 건 거짓이 아니었군.","JPN":"学会の学部長が管理局公認カウンター並の腕利きだという話は嘘ではなかったようだ。","ENG":"So it was true that a Dean of the Society is an Official Administration Counter-level combatant.","TWN":"學會的學院長是管理局認證制裁者級高手，果然不是虛名。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"큭, 이것이 초월지식 학회 당대 처형인의 실력인가?","JPN":"くっ、これが超越知識学会の当代処刑人の強さか？","ENG":"Kgh. Is this the skill of the current executioner of ESPR?","TWN":"嘖，這就是超越學會當代行刑人的實力嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"법학부장, 람다 스파타리…….","JPN":"法学部長、ラムダ・スパタリー……","ENG":"Dean of Law, Lamda Spatari...","TWN":"法學院院長，蘭達．史派特……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"이래저래 얼굴이 너무 알려져 있는 것도 문제로군.","JPN":"顔が知られすぎているというのも困ったものだ。","ENG":"Being this well-known does have its downsides.","TWN":"名氣太大有時候也是種麻煩。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"하지만 나 또한 네놈에 관해 알고 있지.","JPN":"だが、相手のことを熟知しているのは、こちらとて同様。","ENG":"But I am quite familiar with you as well.","TWN":"不過，我也對你略知一二。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"주인을 물고 도망친 성황청의 미친개, 관리국의 1급 수배범, 검은 성자 그리고…….","JPN":"飼い主を噛み逃げ出した聖皇庁の狂犬、管理局の1級手配犯、黒い聖者、そして……","ENG":"The Mad Dog of the Holy Curia that bit his master and ran, the Administration's most-wanted criminal, the Black Helgon, and...","TWN":"咬了主人就逃跑的聖皇廳瘋狗、管理局1級通緝犯、黑色聖者，還有……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L35_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"변절자, 베네딕트 콘스탄틴.","JPN":"変節者、ベネディクト・コンスタンティン。","ENG":"Betrayer, Benedict Constantine.","TWN":"叛徒，本尼迪克特．康斯坦丁。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};